var e=JSON.parse(`[{"id":"L5_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"발각됐어! 달려, 꼬맹아!","JPN":"バレちゃった！　走れ、おこちゃま！","ENG":"We've been found! Run, kid!","TWN":"被發現了！小鬼快跑！"},"stage":{"bg":"BASEMENT","slots":{"L":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L6_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"저도 알고 있어요!","JPN":"わかってるわよ！ ","ENG":"I know that already!","TWN":"我也知道！"},"stage":{"bg":"BASEMENT","slots":{"L":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"MITCH_NPC_NULL_NULL","text":{"KOREA":"이번에는 지하 루트를 공략하는 카나리아─!","JPN":"今度は地下ルートを攻略するカナリア─！","ENG":"Looks like Canary Squad is taking the underground route this time–!","TWN":"這次金絲雀選擇攻陷地下路線—！"},"stage":{"bg":"BASEMENT","slots":{"L":null,"C":{"char_id":"MITCH_NPC_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"MITCH_NPC_NULL_NULL","text":{"KOREA":"냉정하게 분석했을 때, 이쪽 루트도 그리 승산이 높지는 않아.","JPN":"冷静に見て、こっちのルートもあんまり勝算が高くはないよ。","ENG":"Looking at it objectively, their chances of winning by taking this route aren't that high.","TWN":"但冷靜分析後可以發現，這個路線的勝算也不是很高。"},"stage":{"bg":"BASEMENT","slots":{"L":null,"C":{"char_id":"MITCH_NPC_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"MITCH_NPC_NULL_NULL","text":{"KOREA":"카나리아 스쿼드의 전력은 이제 두 사람뿐이지만. 챔피언의 전력은 대부분 건재하니까.","JPN":"カナリア・スクワッドの戦力はもう二人しか残っていないけど。チャンピオンの戦力はほぼそのままだからね。","ENG":"Canary Squad has only two members left, but the champion's team still has a lot of soldiers left.","TWN":"因為金絲雀小隊的戰力現在只剩下二個人，但冠軍的戰力大部分都還在。"},"stage":{"bg":"BASEMENT","slots":{"L":null,"C":{"char_id":"MITCH_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"SHIELD_ADMIN_NULL_NULL","text":{"KOREA":"제길, 그 여자의 부비 트랩이 아직도 남아 있었나!","JPN":"ちくしょう、あの女のブービートラップがまだ残っていたのか！","ENG":"Dammit. That girl's booby traps are still down here!","TWN":"可惡，那個女人埋的地雷陷阱竟然還有！"},"stage":{"bg":"BASEMENT","slots":{"L":null,"C":{"char_id":"SHIELD_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"SHIELD_ADMIN_NULL_NULL","text":{"KOREA":"페인트가 튄 녀석들은 빠져! 우리 모습이 스트리밍에 특정되면 곤란해!","JPN":"ペイントが身体に飛び散った奴らは来るな！　俺たちの姿が配信上で特定されたら困る！","ENG":"Anyone who has paint on them, get out! We can't be seen on camera!","TWN":"有沾到油漆的傢伙都給我走開！這副模樣不能被拍到傳到網路平台上！"},"stage":{"bg":"BASEMENT","slots":{"L":null,"C":{"char_id":"SHIELD_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"SHIELD_ADMIN_NULL_NULL","text":{"KOREA":"나머지는 화물 엘리베이터를 지키러 간다! 움직여!","JPN":"残りは貨物用エレベーターを守りに行くぞ！　動け！","ENG":"The rest of you, guard the cargo elevator! Now, move out!","TWN":"其餘的人去守在貨梯那！行動！"},"stage":{"bg":"BASEMENT","slots":{"L":null,"C":{"char_id":"SHIELD_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"그러니까, 몰래 계단으로 가자고?","JPN":"つまり、こっそり階段で行くってこと？","ENG":"So, you want to sneak up using the stairs?","TWN":"你的意思是，偷偷從樓梯上去？"},"stage":{"bg":"BASEMENT","slots":{"L":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"너 제정신이냐? 싸우기도 전에 탈진하려고?","JPN":"あんた本気？　疲れて戦いにすらならなくなるよ？","ENG":"Are you crazy? We'll be exhausted before we even have a chance to fight.","TWN":"你腦袋沒問題吧？這樣還沒開打就會先體力耗盡吧？"},"stage":{"bg":"BASEMENT","slots":{"L":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"시끄러워요. 그러게 평소에 체력 단련 좀 열심히 하라고 했잖아요.","JPN":"うるさい。だから普段から体力を鍛えろって言っていたでしょ。","ENG":"Shut it. That's why I told you to train every day.","TWN":"你別吵，所以我平常才會一直叫你要做些體能訓練的嘛。"},"stage":{"bg":"BASEMENT","slots":{"L":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"화물 엘리베이터는 상대도 예상하고 있을 거예요. 교전은 최대한 피해야죠.","JPN":"貨物用エレベーターは相手も予想しているはずよ。交戦はできるだけ避けないと。","ENG":"Our opponents will be expecting us to take the elevator. And we have to avoid engagements as much as possible.","TWN":"對方應該也有料到我們會搭貨梯，所以要儘量避免遇到。"},"stage":{"bg":"BASEMENT","slots":{"L":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"야, 옥상까지 100층도 넘는데…!","JPN":"おい、屋上まで100階以上もあるんだぞ……！","ENG":"Hey, but there are 100 floors up to the rooftop...!","TWN":"喂，到頂樓還要爬100多樓欸……！"},"stage":{"bg":"BASEMENT","slots":{"L":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"걱정 마요. 적당한 층에서 엘리베이터로 갈아타면 되니까.","JPN":"心配しないで。適当な階でちゃんとエレベーターに乗るから。","ENG":"Don't worry. We'll use the elevator after going up the stairs to reach a suitable floor.","TWN":"沒事的，我們爬到合適的樓層再搭電梯上去。"},"stage":{"bg":"BASEMENT","slots":{"L":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}}]`);export{e as default};